// Parse Kibana alert payload
const alert = $input.first().json.body || $input.first().json;
const ruleName = alert.rule?.name || alert.kibana?.alert?.rule?.name || 'Unknown rule';
const severity = alert.rule?.severity || alert.kibana?.alert?.severity || 'medium';
const sevMap = { low: 1, medium: 2, high: 3, critical: 4 };
return [{
  json: {
    title: `[VN-SOC] ${ruleName}`,
    description: `Auto-created from Kibana detection rule.\n\nRule: ${ruleName}\nSeverity: ${severity}\nTimestamp: ${alert['@timestamp'] || alert.kibana?.alert?.original_time || new Date().toISOString()}\nSource event: ${JSON.stringify(alert, null, 2).substring(0, 2000)}`,
    severity: sevMap[severity.toLowerCase()] || 2,
    tlp: 2,
    pap: 2,
    tags: ['vn-soc-lab', 'auto-created', `severity-${severity}`],
    sourceRef: alert.kibana?.alert?.uuid || alert._id || `vnsoc-${Date.now()}`,
    observables: [
      alert['source.ip'] ? { dataType: 'ip', data: alert['source.ip'], message: 'source IP' } : null,
      alert['url.original'] ? { dataType: 'url', data: alert['url.original'], message: 'URL probed' } : null,
      alert['user_agent.original'] ? { dataType: 'user-agent', data: alert['user_agent.original'], message: 'UA' } : null,
    ].filter(Boolean)
  }
}];
